import{_ as a,X as r,Y as i,$ as h,a1 as d,a2 as t,a3 as n,F as s,a0 as l}from"./framework-abbf9d44.js";const p={},c=n('<h1 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h1><h2 id="接收工作" tabindex="-1"><a class="header-anchor" href="#接收工作" aria-hidden="true">#</a> 接收工作</h2><p>一定要搞清楚交付的标准，不清楚标准就意味着返工的概率极大。如何搞清楚，工作需要达到的状态？</p><h3 id="smart公式" tabindex="-1"><a class="header-anchor" href="#smart公式" aria-hidden="true">#</a> SMART公式</h3><ul><li>具体化（Specific）：明确具体指标和细节。</li><li>可衡量（Measurable）：确保目标可以量化。</li><li>可实现（Achievable）：目标可行，不理想化。</li><li>相关性（Relevant）：与总目标相关联。</li><li>有时限（Time-bound）：明确的完成时间。</li></ul><h2 id="请示工作" tabindex="-1"><a class="header-anchor" href="#请示工作" aria-hidden="true">#</a> 请示工作</h2><p>比如，工作中遇到问题等，不要上来就问该怎么办？需要带着方案（ &gt;2个 ）去。用RIDE模型，说服老板支持你。</p><h3 id="ride模型" tabindex="-1"><a class="header-anchor" href="#ride模型" aria-hidden="true">#</a> RIDE模型</h3><p>R-risk：风险，目前的困境</p><p>I-interest： 利益，引入共同利益</p><p>D-difference： 差异，A方案和B方案的区别</p><p>E-effect：影响，适当体现一些缺点（全挑好的说不真实）</p><h2 id="汇报工作" tabindex="-1"><a class="header-anchor" href="#汇报工作" aria-hidden="true">#</a> 汇报工作</h2><h3 id="prep" tabindex="-1"><a class="header-anchor" href="#prep" aria-hidden="true">#</a> PREP</h3><ul><li>Point（结论先行）：上来就给结论，直击重点。</li><li>Reason（再讲理由）：陈述原因，给出有说服力的依据</li><li>Example（拿出事例）：最好给一个实例</li><li>Point（重述结论）：将发散的思维回归结论，强化观点</li></ul><h2 id="分享工作" tabindex="-1"><a class="header-anchor" href="#分享工作" aria-hidden="true">#</a> 分享工作</h2><p>如果做团队分享，一定要多维分析，不可泛泛而谈</p><h3 id="_5w2h" tabindex="-1"><a class="header-anchor" href="#_5w2h" aria-hidden="true">#</a> 5W2H</h3><p>从7个维度思考，广泛应用于产品、业务、项目运营可行性分析，问题解决和落地方法论。</p><p>What： 产品背景</p><p>Who： 目标人群</p><p>Why： 预期目标</p><p>Where： 使用场景</p><p>When：需求节点</p><p>How：如何验证</p><p>How much：用多少资源</p><p>不仅分享可用，很多场景都可以套用。业务/场景分析等</p><h2 id="复盘-sop总结" tabindex="-1"><a class="header-anchor" href="#复盘-sop总结" aria-hidden="true">#</a> 复盘(SOP总结)</h2><h3 id="grai法则" tabindex="-1"><a class="header-anchor" href="#grai法则" aria-hidden="true">#</a> GRAI法则</h3><p>G-Goal：回顾目标</p><p>R-Result：评估结果，方向校准，数据验证</p><p>A-Analysis：分析成功/失败原因，表层/深层原因，偶发性和必然性</p><p>I-Insight：总结规律方法论</p><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2>',34);function o(u,f){const e=s("RouterLink");return r(),i("div",null,[c,h("p",null,[d(e,{to:"/read/65%E4%B8%AA%E6%80%9D%E7%BB%B4%E6%A8%A1%E5%9E%8B.html"},{default:t(()=>[l("65个思维模型")]),_:1})])])}const x=a(p,[["render",o],["__file","方法论.html.vue"]]);export{x as default};
